    const itemId = parseInt(c.req.param('itemId'))
    if (isNaN(weekId) || isNaN(itemId)) {
      return c.json({ data: null, error: 'ID không hợp lệ' }, 400)
    }

    const { data: week, error: weekError } = await supabase
