      return c.json({ data: null, error: 'Không tìm thấy tuần đặt hàng' }, 404)
    }
    if (week.status !== 'CONFIRMED') {
      return c.json({ data: null, error: 'Chỉ có thể đánh dấu hoàn tất khi tuần ở trạng thái CONFIRMED' }, 400)
