import { ref, computed } from 'vue'
import { deptAllocationService } from '@/services/deptAllocationService'
import { useSnackbar } from '../useSnackbar'
import type {
  DeptAllocationSummary,
  DeptAllocationLog,
} from '@/types/thread/deptAllocation'

export function useDeptAllocation() {
  const snackbar = useSnackbar()
  const summary = ref<DeptAllocationSummary | null>(null)
  const logs = ref<DeptAllocationLog[]>([])
  const isLoading = ref(false)
  const isAllocating = ref(false)

  const hasAllocations = computed(() =>
    (summary.value?.total_allocated ?? 0) > 0
  )

  function getDeptInfo(department: string) {
    if (!summary.value) return null
    return summary.value.allocated.find(a => a.department === department) ?? null
  }

  async function loadSummary(poId: number, styleId: number, styleColorId: number) {
    isLoading.value = true
    try {
      summary.value = await deptAllocationService.getSummary(poId, styleId, styleColorId)
    } catch (err) {
      console.error('[useDeptAllocation] loadSummary error:', err)
      summary.value = null
    } finally {
      isLoading.value = false
    }
  }

  async function allocate(data: {
    po_id: number
    style_id: number
    style_color_id: number
    department: string
    add_quantity: number
    created_by: string
  }) {
    isAllocating.value = true
    try {
      const result = await deptAllocationService.allocate(data)
      snackbar.success(`Đã phân bổ ${result.added_quantity} SP cho ${data.department}`)
      await loadSummary(data.po_id, data.style_id, data.style_color_id)
      return result
    } catch (err: any) {
      snackbar.error(err.message || 'Không thể phân bổ sản phẩm')
      throw err
    } finally {
      isAllocating.value = false
    }
  }

  async function loadLogs(
    poId: number,
    styleId: number,
    styleColorId: number,
    department?: string
  ) {
    try {
      logs.value = await deptAllocationService.getLogs(poId, styleId, styleColorId, department)
    } catch (err) {
      console.error('[useDeptAllocation] loadLogs error:', err)
      logs.value = []
    }
  }

  function reset() {
    summary.value = null
    logs.value = []
  }

  return {
    summary,
    logs,
    isLoading,
    isAllocating,
    hasAllocations,
    getDeptInfo,
    loadSummary,
    allocate,
    loadLogs,
    reset,
  }
}

import { useQuasar } from 'quasar'
import { ref } from 'vue'

export function useDarkMode() {
  const $q = useQuasar()
  const preference = ref<'auto' | 'light' | 'dark'>(
    (localStorage.getItem('quasar-dark-mode') as any) || 'auto'
  )

  const applyMode = (mode: 'auto' | 'light' | 'dark') => {
    if (mode === 'auto') {
      $q.dark.set('auto')
    } else {
      $q.dark.set(mode === 'dark')
    }
  }

  const setMode = (mode: 'auto' | 'light' | 'dark') => {
    preference.value = mode
    localStorage.setItem('quasar-dark-mode', mode)
    applyMode(mode)
  }

  const toggle = () => {
    if (preference.value === 'light') {
      setMode('dark')
    } else if (preference.value === 'dark') {
      setMode('auto')
    } else {
      setMode('light')
    }
  }

  const isDark = () => $q.dark.isActive

  const init = () => {
    applyMode(preference.value)
  }

  return {
    preference,
    setMode,
    toggle,
    isDark,
    init
  }
}

import { ref } from 'vue'

export function useDialog<T = any>(defaultValue?: T) {
  const isOpen = ref(false)
  const data = ref<T | undefined>(defaultValue)

  const open = (payload?: T) => {
    data.value = payload
    isOpen.value = true
  }

  const close = () => {
    isOpen.value = false
    data.value = defaultValue
  }

  const toggle = () => {
    isOpen.value = !isOpen.value
  }

  return {
    isOpen,
    data,
    open,
    close,
    toggle
  }
}

import { ref, computed, onMounted, onUnmounted } from 'vue'
import { useSnackbar } from './useSnackbar'

export interface PendingOperation {
  id: string
  type: 'RECEIVE' | 'ISSUE' | 'RECOVERY' | 'WEIGH'
  endpoint: string
  method: 'POST' | 'PUT' | 'DELETE'
  data: Record<string, any>
  timestamp: number
  retries: number
}

const DB_NAME = 'thread-offline-db'
const STORE_NAME = 'pending-operations'

export function useOfflineSync() {
  const isOnline = ref(navigator.onLine)
  const pendingOperations = ref<PendingOperation[]>([])
  const isSyncing = ref(false)
  const lastSyncTime = ref<Date | null>(null)
  const error = ref<string | null>(null)

  const snackbar = useSnackbar()

  let db: IDBDatabase | null = null

  // Computed
  const pendingCount = computed(() => pendingOperations.value.length)
  const hasPending = computed(() => pendingCount.value > 0)

  // Initialize IndexedDB
  const initDB = (): Promise<IDBDatabase> => {
    return new Promise((resolve, reject) => {
      const request = indexedDB.open(DB_NAME, 1)

      request.onerror = () => reject(request.error)

      request.onsuccess = () => {
        db = request.result
        resolve(db)
      }

      request.onupgradeneeded = (event) => {
        const database = (event.target as IDBOpenDBRequest).result
        if (!database.objectStoreNames.contains(STORE_NAME)) {
          database.createObjectStore(STORE_NAME, { keyPath: 'id' })
        }
      }
    })
  }

  // Load pending operations from IndexedDB
  const loadPending = async (): Promise<void> => {
    if (!db) await initDB()

    return new Promise((resolve, reject) => {
      const transaction = db!.transaction(STORE_NAME, 'readonly')
      const store = transaction.objectStore(STORE_NAME)
      const request = store.getAll()

      request.onsuccess = () => {
        pendingOperations.value = request.result || []
        resolve()
      }
      request.onerror = () => reject(request.error)
    })
  }

  // Add operation to queue
  const addPending = async (
    operation: Omit<PendingOperation, 'id' | 'timestamp' | 'retries'>
  ): Promise<string> => {
    if (!db) await initDB()

    const op: PendingOperation = {
      ...operation,
      id: `${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
      timestamp: Date.now(),
      retries: 0,
    }

    return new Promise((resolve, reject) => {
      const transaction = db!.transaction(STORE_NAME, 'readwrite')
      const store = transaction.objectStore(STORE_NAME)
      const request = store.add(op)

      request.onsuccess = () => {
        pendingOperations.value.push(op)
        resolve(op.id)
      }
      request.onerror = () => reject(request.error)
    })
  }

  // Remove operation from queue
  const removePending = async (id: string): Promise<void> => {
    if (!db) await initDB()

    return new Promise((resolve, reject) => {
      const transaction = db!.transaction(STORE_NAME, 'readwrite')
      const store = transaction.objectStore(STORE_NAME)
      const request = store.delete(id)

      request.onsuccess = () => {
        pendingOperations.value = pendingOperations.value.filter((op) => op.id !== id)
        resolve()
      }
      request.onerror = () => reject(request.error)
    })
  }

  // Sync a single operation
  const syncOperation = async (operation: PendingOperation): Promise<boolean> => {
    try {
      const response = await fetch(operation.endpoint, {
        method: operation.method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(operation.data),
      })

      if (response.ok) {
        await removePending(operation.id)
        return true
      } else {
        // Update retry count
        operation.retries++
        if (operation.retries >= 3) {
          // Move to failed after 3 retries
          error.value = `Không thể đồng bộ: ${operation.type}`
        }
        return false
      }
    } catch {
      return false
    }
  }

  // Sync all pending operations
  const syncAll = async (): Promise<void> => {
    if (!isOnline.value || isSyncing.value || !hasPending.value) return

    isSyncing.value = true
    error.value = null

    try {
      // Sort by timestamp (oldest first)
      const sorted = [...pendingOperations.value].sort((a, b) => a.timestamp - b.timestamp)

      let successCount = 0
      let failCount = 0

      for (const operation of sorted) {
        const success = await syncOperation(operation)
        if (success) {
          successCount++
        } else {
          failCount++
        }
      }

      lastSyncTime.value = new Date()

      if (successCount > 0) {
        snackbar.success(`Đã đồng bộ ${successCount} thao tác`)
      }
      if (failCount > 0) {
        snackbar.warning(`${failCount} thao tác chưa thể đồng bộ`)
      }
    } finally {
      isSyncing.value = false
    }
  }

  // Queue operation (online: execute immediately, offline: queue)
  const queueOperation = async (
    type: PendingOperation['type'],
    endpoint: string,
    method: PendingOperation['method'],
    data: Record<string, any>
  ): Promise<{ success: boolean; queued: boolean; result?: any }> => {
    if (isOnline.value) {
      try {
        const response = await fetch(endpoint, {
          method,
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(data),
        })

        if (response.ok) {
          const result = await response.json()
          return { success: true, queued: false, result }
        }
      } catch {
        // Fall through to queue
      }
    }

    // Queue for later
    await addPending({ type, endpoint, method, data })
    snackbar.info('Thao tác đã lưu, sẽ đồng bộ khi có mạng')
    return { success: false, queued: true }
  }

  // Online/Offline handlers
  const handleOnline = () => {
    isOnline.value = true
    snackbar.success('Đã kết nối mạng')
    syncAll()
  }

  const handleOffline = () => {
    isOnline.value = false
    snackbar.warning('Mất kết nối mạng - Chế độ offline')
  }

  // Clear all pending
  const clearAll = async (): Promise<void> => {
    if (!db) await initDB()

    return new Promise((resolve, reject) => {
      const transaction = db!.transaction(STORE_NAME, 'readwrite')
      const store = transaction.objectStore(STORE_NAME)
      const request = store.clear()

      request.onsuccess = () => {
        pendingOperations.value = []
        resolve()
      }
      request.onerror = () => reject(request.error)
    })
  }

  // Lifecycle
  onMounted(async () => {
    await initDB()
    await loadPending()

    window.addEventListener('online', handleOnline)
    window.addEventListener('offline', handleOffline)

    // Try to sync on mount if online
    if (isOnline.value && hasPending.value) {
      syncAll()
    }
  })

  onUnmounted(() => {
    window.removeEventListener('online', handleOnline)
    window.removeEventListener('offline', handleOffline)
  })

  return {
    // State
    isOnline,
    pendingOperations,
    pendingCount,
    hasPending,
    isSyncing,
    lastSyncTime,
    error,

    // Methods
    addPending,
    removePending,
    syncAll,
    queueOperation,
    clearAll,
    loadPending,
  }
}

