   * Cập nhật định mức (quota_cones) cho một loại chỉ
   * @param weekId - Weekly order ID
   * @param threadTypeId - Thread type ID
   * @param quotaCones - New quota value
   */
  async updateQuotaCones(weekId: number, threadTypeId: number, quotaCones: number): Promise<void> {
    const response = await fetchApi<ApiResponse<unknown>>(`${BASE}/items/${weekId}/quota`, {
      method: 'PUT',
      body: JSON.stringify({ thread_type_id: threadTypeId, quota_cones: quotaCones }),
    })

    if (response.error) {
      throw new Error(response.error)
    }
  },

  async getOrderedQuantities(
    pairs: Array<{ po_id: number; style_id: number }>,
    excludeWeekId?: number,
  ): Promise<OrderedQuantityInfo[]> {
    const searchParams = new URLSearchParams()
    searchParams.append('po_style_pairs', JSON.stringify(pairs))
    if (excludeWeekId) searchParams.append('exclude_week_id', String(excludeWeekId))

    const response = await fetchApi<ApiResponse<OrderedQuantityInfo[]>>(
      `${BASE}/ordered-quantities?${searchParams.toString()}`,
    )

    if (response.error) {
      throw new Error(response.error)
    }

    return response.data || []
  },

  async getHistoryByWeek(
    filters: HistoryByWeekFilter,
  ): Promise<{ data: WeekHistoryGroup[]; pagination: { page: number; limit: number; total: number; totalPages: number } }> {
    const searchParams = new URLSearchParams()
    if (filters.po_id) searchParams.append('po_id', String(filters.po_id))
    if (filters.style_id) searchParams.append('style_id', String(filters.style_id))
    if (filters.from_date) searchParams.append('from_date', filters.from_date)
    if (filters.to_date) searchParams.append('to_date', filters.to_date)
    if (filters.status) searchParams.append('status', filters.status)
    if (filters.created_by) searchParams.append('created_by', filters.created_by)
    if (filters.page) searchParams.append('page', String(filters.page))
    if (filters.limit) searchParams.append('limit', String(filters.limit))

    const response = await fetchApi<any>(
      `${BASE}/history-by-week?${searchParams.toString()}`,
    )

    if (response.error) {
      throw new Error(response.error)
    }

    return {
      data: response.data || [],
      pagination: response.pagination || { page: 1, limit: 10, total: 0, totalPages: 0 },
    }
  },

  async createLoan(toWeekId: number, data: CreateLoanDTO): Promise<ThreadOrderLoan> {
    const response = await fetchApi<ApiResponse<ThreadOrderLoan>>(`${BASE}/${toWeekId}/loans`, {
      method: 'POST',
      body: JSON.stringify(data),
    })

    if (response.error) {
      throw new Error(response.error)
    }

    if (!response.data) {
      throw new Error('Không thể tạo khoản mượn chỉ')
    }

    return response.data
  },

  async createBatchLoan(toWeekId: number, data: CreateBatchLoanDTO): Promise<BatchLoanResult> {
    const response = await fetchApi<ApiResponse<BatchLoanResult>>(`${BASE}/${toWeekId}/loans/batch`, {
      method: 'POST',
      body: JSON.stringify(data),
    })

    if (response.error) {
      throw new Error(response.error)
    }

    if (!response.data) {
      throw new Error('Không thể tạo khoản mượn chỉ')
    }

    return response.data
  },

  async getLoans(weekId: number): Promise<{ all: ThreadOrderLoan[]; given: ThreadOrderLoan[]; received: ThreadOrderLoan[] }> {
    const response = await fetchApi<ApiResponse<{ all: ThreadOrderLoan[]; given: ThreadOrderLoan[]; received: ThreadOrderLoan[] }>>(`${BASE}/${weekId}/loans`)

    if (response.error) {
      throw new Error(response.error)
    }

    return response.data || { all: [], given: [], received: [] }
  },

  async getReservations(weekId: number): Promise<{ cones: ReservedCone[]; summary: Array<{ thread_type_id: number; count: number; total_meters: number }>; total_cones: number }> {
    const response = await fetchApi<ApiResponse<{ cones: ReservedCone[]; summary: Array<{ thread_type_id: number; count: number; total_meters: number }>; total_cones: number }>>(`${BASE}/${weekId}/reservations`)

    if (response.error) {
      throw new Error(response.error)
    }

    return response.data || { cones: [], summary: [], total_cones: 0 }
  },

  /**
   * Get all loans across all weeks
   */
  async getAllLoans(): Promise<ThreadOrderLoan[]> {
    const response = await fetchApi<ApiResponse<ThreadOrderLoan[]>>(`${BASE}/loans/all`)

    if (response.error) {
      throw new Error(response.error)
    }

    return response.data || []
  },

  async getLoanSummary(): Promise<LoanDashboardSummary[]> {
    const response = await fetchApi<ApiResponse<LoanDashboardSummary[]>>(`${BASE}/loans/summary`)

    if (response.error) {
      throw new Error(response.error)
    }

    return response.data || []
  },

  /**
   * Task 6.2: Get reservation summary for a week
   * Returns per-thread summary with needed, reserved, shortage, available_stock
   */
  async getReservationSummary(weekId: number): Promise<ReservationSummary[]> {
    const response = await fetchApi<ApiResponse<ReservationSummary[]>>(`${BASE}/${weekId}/reservation-summary`)

    if (response.error) {
      throw new Error(response.error)
    }

    return response.data || []
  },

  /**
   * Task 6.1: Reserve available stock for a confirmed week
   * Creates loan record with from_week_id = NULL
   */
  async reserveFromStock(weekId: number, dto: ReserveFromStockDTO): Promise<ReserveFromStockResult> {
    const response = await fetchApi<ApiResponse<ReserveFromStockResult>>(`${BASE}/${weekId}/reserve-from-stock`, {
      method: 'POST',
      body: JSON.stringify(dto),
    })

    if (response.error) {
      throw new Error(response.error)
    }

    if (!response.data) {
      throw new Error('Không thể lấy từ tồn kho')
    }

    return response.data
  },

  async getAssignmentSummary(status?: string): Promise<AssignmentSummaryRow[]> {
    const params = new URLSearchParams()
    if (status) params.append('status', status)
    const queryString = params.toString()
    const url = queryString ? `${BASE}/assignment-summary?${queryString}` : `${BASE}/assignment-summary`
    const response = await fetchApi<ApiResponse<AssignmentSummaryRow[]>>(url)
    if (response.error) throw new Error(response.error)
    return response.data || []
  },

  async getLoanDetailByType(weekId: number): Promise<LoanDetailByType[]> {
    const response = await fetchApi<ApiResponse<LoanDetailByType[]>>(`${BASE}/${weekId}/loan-detail-by-type`)
    if (response.error) throw new Error(response.error)
    return response.data || []
  },

  async getReturnLogs(loanId: number): Promise<LoanReturnLog[]> {
    const response = await fetchApi<ApiResponse<LoanReturnLog[]>>(`${BASE}/loans/${loanId}/return-logs`)
    if (response.error) throw new Error(response.error)
    return response.data || []
  },

  async manualReturn(weekId: number, loanId: number, dto: ManualReturnDTO): Promise<ManualReturnResult> {
    const response = await fetchApi<ApiResponse<ManualReturnResult>>(
      `${BASE}/${weekId}/loans/${loanId}/manual-return`,
      { method: 'POST', body: JSON.stringify(dto) },
    )
    if (response.error) throw new Error(response.error)
    if (!response.data) throw new Error('Không thể trả chỉ')
    return response.data
  },

  async markItemComplete(weekId: number, itemId: number): Promise<ThreadOrderItemCompletion> {
    const response = await fetchApi<ApiResponse<ThreadOrderItemCompletion>>(
      `${BASE}/${weekId}/items/${itemId}/complete`,
      { method: 'POST' },
    )
    if (response.error) throw new Error(response.error)
    if (!response.data) throw new Error('Không thể đánh dấu hoàn tất')
    return response.data
  },

  async unmarkItemComplete(weekId: number, itemId: number): Promise<void> {
    const response = await fetchApi<ApiResponse<null>>(
      `${BASE}/${weekId}/items/${itemId}/complete`,
      { method: 'DELETE' },
    )
    if (response.error) throw new Error(response.error)
  },

  async getCompletions(weekId: number): Promise<ThreadOrderItemCompletion[]> {
    const response = await fetchApi<ApiResponse<ThreadOrderItemCompletion[]>>(
      `${BASE}/${weekId}/completions`,
    )
    if (response.error) throw new Error(response.error)
    return response.data || []
  },

  async getSurplusPreview(weekId: number): Promise<SurplusPreview> {
    const response = await fetchApi<ApiResponse<SurplusPreview>>(
      `${BASE}/${weekId}/surplus-preview`,
    )
    if (response.error) throw new Error(response.error)
    if (!response.data) throw new Error('Không thể tải preview')
    return response.data
  },

  async releaseSurplus(weekId: number): Promise<ReleaseSurplusResult> {
    const response = await fetchApi<ApiResponse<ReleaseSurplusResult>>(
      `${BASE}/${weekId}/release-surplus`,
      { method: 'POST' },
    )
    if (response.error) throw new Error(response.error)
    if (!response.data) throw new Error('Không thể trả dư')
    return response.data
  },

  async batchComplete(itemIds: number[]): Promise<{ completed_count: number; skipped_count: number }> {
    const response = await fetchApi<ApiResponse<{ completed_count: number; skipped_count: number }>>(
      `${BASE}/batch-complete`,
      {
        method: 'POST',
        body: JSON.stringify({ item_ids: itemIds }),
      },
    )
    if (response.error) throw new Error(response.error)
    if (!response.data) throw new Error('Không thể đánh dấu hoàn tất')
    return response.data
  },

  async completionLookup(poId: number, styleId: number, styleColorId: number | null): Promise<{ weeks: Array<{ week_id: number; week_name: string; item_ids: number[] }> }> {
    const response = await fetchApi<ApiResponse<{ weeks: Array<{ week_id: number; week_name: string; item_ids: number[] }> }>>(
      `${BASE}/completion-lookup`,
      {
        method: 'POST',
        body: JSON.stringify({ po_id: poId, style_id: styleId, style_color_id: styleColorId }),
      },
    )
    if (response.error) throw new Error(response.error)
    if (!response.data) throw new Error('Không thể tra cứu tuần hoàn tất')
    return response.data
  },
}

